function preferredCodexHighRoute(row = {}, role = "executor") {
  const provider = String(row.provider || "openai-codex").trim() || "openai-codex";
  const model = String(row.model || "").trim();
  const effort = normalizeRouteEffort(row.effort || row.reasoningEffort, "high");
  const normalizedProvider = provider.toLowerCase();
  const normalizedModel = model.toLowerCase();
  const promotedEffort = ["medium", "default", ""].includes(effort) ? "high" : effort;
  const providerFromModel = normalizedModel.includes("minimax")
    ? "minimax"
    : normalizedProvider === "openai" && (normalizedModel.includes("gpt") || normalizedModel.includes("codex") || !model)
      ? "openai-codex"
      : provider;
  const shouldPromote =
    (normalizedProvider === "openai-codex" || normalizedProvider === "openai") &&
    (!model || normalizedModel.includes("gpt-5.3-codex") || effort === "medium" || effort === "default");
  if (!shouldPromote) {
    return {
      ...row,
      role: row.role || role,
      provider: providerFromModel,
      model: model || (providerFromModel === "openai-codex" ? "gpt-5.5" : model),
      effort: promotedEffort,
    };
  }
  return {
    ...row,
    role: row.role || role,
    provider: "openai-codex",
    model: "gpt-5.5",
    effort: "high",
    source: row.source || "operator_preferred_default",
    preferenceApplied: "codex_5_5_high",
  };
}

function buildMissionRouteOverrides(provider, model, effort) {
  const selectedProvider = String(provider || "openai-codex").trim() || "openai-codex";
  const selectedModel = String(model || "").trim();
  const selectedEffort = normalizeRouteEffort(effort, "high");
  if (!selectedModel) {
    return [];
  }
  if (selectedProvider.toLowerCase().includes("minimax") || selectedModel.toLowerCase().includes("minimax")) {
    return [
      { role: "planner", provider: "openai-codex", model: "gpt-5.5", effort: "high" },
      { role: "executor", provider: "minimax", model: selectedModel, effort: selectedEffort },
      { role: "verifier", provider: "openai-codex", model: "gpt-5.5", effort: "high" },
    ];
  }
  return ROUTE_ROLE_OPTIONS.map(role => ({
    role,
    provider: selectedProvider,
    model: selectedModel,
    effort: selectedEffort,
  }));
}

function firstLaunchParam(searchParams, names) {
  for (const name of names) {
    const value = String(searchParams.get(name) || "").trim();
    if (value) {
      return value;
    }
  }
  return "";
}

function optionValueFromLaunchParam(searchParams, names, allowedValues, fallback, aliases = {}) {
  const requested = firstLaunchParam(searchParams, names);
  if (!requested) {
    return fallback;
  }
  const normalized = requested.toLowerCase();
  const aliased = aliases[normalized] || requested;
  return (
    allowedValues.find(value => value === aliased) ||
    allowedValues.find(value => value.toLowerCase() === normalized) ||
    fallback
  );
}
