          snapshot: null,
          summary: liveSummary,
          onboarding: liveSummary?.onboarding || current.onboarding || null,
          pendingApprovals: Array.isArray(pendingApprovals) ? pendingApprovals : [],
          pendingQuestions: Array.isArray(pendingQuestions) ? pendingQuestions : [],
